 15	import { FilterIcon } from '@patternfly/react-icons';
 16	
 17	import FormPFSelect from '../FormPFSelect/FormPFSelect';
 18	
 19	import { Filter, FilterKeys, generateRowFilters, intersection } from './utils';
 20	
 21	type RowFiltersProps = {
 22	  filters: Filter;
 23	  filtersNameMap: FilterKeys;
 24	  generatedRowFilters: ReturnType<typeof generateRowFilters>;
 25	  rowFilters: RowFilter[];
 26	  selectedRowFilters: string[];
 27	  updateRowFilterSelected: (id: string[]) => void;
 28	};
 29	
 30	const RowFilters: FC<RowFiltersProps> = ({
 31	  filters,
 32	  filtersNameMap,
 33	  generatedRowFilters,
 34	  rowFilters,
 35	  selectedRowFilters,
 36	  updateRowFilterSelected,
 37	}) => {
 38	  const { t } = useKubevirtTranslation();
 39	  const clearAllRowFilter = (f: string) => {
 40	    updateRowFilterSelected(intersection(filters[f], selectedRowFilters));
 41	  };
 42	
 43	  const onRowFilterSelect = (_, filterID: string) => {
 44	    updateRowFilterSelected([filterID]);
 45	  };
 46	
 47	  if (isEmpty(rowFilters)) return null;
 48	
 49	  return (
 50	    <ToolbarItem>
 51	      {Object.keys(filters).reduce(
 52	        (acc, key) => (
 53	          <ToolbarFilter
 54	            labelGroupCollapsedText={t('{{numRemaining}} more', {
 55	              numRemaining: '${remaining}',
 56	            })}
 57	            labels={intersection(selectedRowFilters, filters[key]).map((item) => {
 58	              return {
 59	                key: item,
 60	                node: filtersNameMap[item],
 61	              };
 62	            })}
 63	            categoryName={key}
 64	            labelGroupExpandedText={t('Show less')}
 65	            deleteLabel={(filter, chip: ToolbarChip) => updateRowFilterSelected([chip.key])}
 66	            deleteLabelGroup={() => clearAllRowFilter(key)}
 67	            key={key}
 68	          >
 69	            {acc}
 70	          </ToolbarFilter>
 71	        ),
 72	        <div data-test-id="filter-dropdown-toggle">
 73	          <FormPFSelect
 74	            toggleProps={{
 75	              icon: (
 76	                <Icon className="span--icon__right-margin">
 77	                  <FilterIcon />
 78	                </Icon>
 79	              ),
 80	            }}
 81	            closeOnSelect={false}
 82	            onSelect={onRowFilterSelect}
 83	            selected={selectedRowFilters}
 84	            selectedLabel={t('Filter')}
 85	          >
 86	            {generatedRowFilters.map((rowFilter) => (
 87	              <SelectGroup key={rowFilter.filterGroupName} label={rowFilter.filterGroupName}>
 88	                {rowFilter.items?.map?.((item) =>
 89	                  item.hideIfEmpty && (item.count === 0 || item.count === '0') ? (
 90	                    <></>
 91	                  ) : (
 92	                    <SelectOption
 93	                      data-test-row-filter={item.id}
 94	                      hasCheckbox
 95	                      isSelected={selectedRowFilters?.includes(item.id)}
 96	                      key={item.id}
 97	                      value={item.id}
 98	                    >
 99	                      <span className="co-filter-dropdown-item__name">{item.title}</span>
100	                      <Badge isRead key={item.id}>
101	                        {item.count}
102	                      </Badge>
103	                    </SelectOption>
104	                  ),
105	                )}
106	              </SelectGroup>
107	            ))}
108	          </FormPFSelect>
109	        </div>,
110	      )}
111	    </ToolbarItem>
112	  );
113	};
114	
115	export default RowFilters;

